const results = [];

  for (const item of $input.all()) {
    const base64 = item.binary?.data?.data;
    const mimeType = item.binary?.data?.mimeType || 'image/jpeg';

    results.push({
      json: {
        imageBase64: base64,
        mimeType: mimeType
      }
    });
  }

  return results;

const items = $input.all();
  const analyses = [];

  for (let i = 0; i < items.length; i++) {
    const text = items[i].json?.content?.[0]?.text || '';
    analyses.push(`[사진 ${i+1}]\n${text}`);
  }

  const combinedAnalysis = analyses.join('\n\n');

  const prompt = `당신은 '아빠와 딸의 성장여행' 블로그를 운영하는 아빠 월양입니다.
  아래 사진 분석 결과를 바탕으로 네이버 블로그 포스팅 초안을 작성해주세요.

  [글쓰기 필수 규칙]
  ✅ 문체: ~해요 체 완전 통일 (~입니다/됩니다 절대 금지)
  ✅ 호칭: 아이→따따 / 배우자→따따엄마 / 필자→월양 또는 아빠 월양 / 독자→엄빠
  ✅ 제목: 핵심 키워드 맨 앞, 60자 이내, ~해요 말투 없음
  ✅ 글 구조: 결론 먼저(체크리스트) → 방문 배경 → 현장 디테일(따따 반응 포함) → 실전 루트(번호형) → 총평
  + 행동 유도 → 해시태그
  ✅ 문장: 60자 이내, 단락 3~4줄 이내, 단락 사이 구분선(---) 삽입
  ✅ 사진 위치: 각 단락에 [📷 사진 위치 — 설명] 형식으로 표기
  ✅ 체류 장치: 도입부 체크리스트, 중간 훅("근데 진짜 좋았던 건요"), 실전 루트 번호형
  ✅ 해시태그: 30개, 한 줄 복사 형식
  ✅ 글자 수: 본문 1500~2000자 (해시태그 제외)

  [여행 사진 분석 결과]
  ${combinedAnalysis}

  위 내용으로 블로그 포스팅 초안을 작성해주세요.`;

  const requestBody = JSON.stringify({
    model: "claude-sonnet-4-6",
    max_tokens: 4096,
    messages: [{
      role: "user",
      content: prompt
    }]
  });

  return [{
    json: {
      combinedAnalysis: combinedAnalysis,
      photoCount: items.length,
      requestBody: requestBody
    }
  }];

const blogText = $input.first().json.content[0].text;
  const title = blogText.split('\n')[0].replace(/^#+ /, '').trim();

  const bodyText = blogText.length > 1900
    ? blogText.slice(0, 1900) + '...(전체 내용은 페이지 안에 있어요)'
    : blogText;

  const maxLen = 1900;
  const chunks = [];
  for (let i = 0; i < blogText.length; i += maxLen) {
    chunks.push(blogText.slice(i, i + maxLen));
  }

  const children = chunks.map(chunk => ({
    object: "block",
    type: "paragraph",
    paragraph: {
      rich_text: [{ type: "text", text: { content: chunk } }]
    }
  }));

  const requestBody = JSON.stringify({
    parent: { database_id: "383715aca6d08086888af28190aa4a93" },
    properties: {
      "제목": {
        title: [{ type: "text", text: { content: title } }]
      },
      "본문": {
        rich_text: [{ type: "text", text: { content: bodyText } }]
      }
    },
    children: children
  });

  return [{ json: { requestBody } }];
